<?php
namespace App\Controllers;
use App\Core\Auth;use App\Core\Database;use App\Core\View;use App\Services\AuditService;
final class AttachmentPolicyController{
 public function index():void{Auth::requireRole('owner','administrator');View::render('portal/attachment-policies/index',['title'=>'Inspection Media Policies','policies'=>Database::connection()->query('SELECT * FROM inspection_attachment_policies ORDER BY active DESC,id')->fetchAll()],'portal');}
 public function store():void{Auth::requireRole('owner','administrator');verify_csrf();Database::connection()->prepare('INSERT INTO inspection_attachment_policies(name,attachment_type,retain_days,create_thumbnail,thumbnail_width,active,created_by) VALUES(?,?,?,?,?,?,?)')->execute([trim($_POST['name']),$_POST['attachment_type']??'all',($_POST['retain_days']??'')!==''?(int)$_POST['retain_days']:null,isset($_POST['create_thumbnail'])?1:0,max(120,(int)($_POST['thumbnail_width']??480)),isset($_POST['active'])?1:0,Auth::id()]);AuditService::log('inspection_attachment_policy.created','inspection_attachment_policy',(int)Database::connection()->lastInsertId());redirect('/portal/attachment-policies');}
 public function update(int $id):void{Auth::requireRole('owner','administrator');verify_csrf();Database::connection()->prepare('UPDATE inspection_attachment_policies SET name=?,attachment_type=?,retain_days=?,create_thumbnail=?,thumbnail_width=?,active=? WHERE id=?')->execute([trim($_POST['name']),$_POST['attachment_type']??'all',($_POST['retain_days']??'')!==''?(int)$_POST['retain_days']:null,isset($_POST['create_thumbnail'])?1:0,max(120,(int)($_POST['thumbnail_width']??480)),isset($_POST['active'])?1:0,$id]);AuditService::log('inspection_attachment_policy.updated','inspection_attachment_policy',$id);redirect('/portal/attachment-policies');}
}
